code:
node Task {
    has title: str;
    has minutes: int;

    def label() -> str {
        return self.title;
    }
}

walker TaskCounter {
    has seen: int = 0;
}

def total_minutes(items: list[int]) -> int {
    total: int = 0;
    for minutes in items {
        total = total + minutes;
    }
    return total;
}

with entry {
    root() ++> node::Task(title="design", minutes=30);
    root() ++> node::Task(title="build", minutes=90);
    print(total_minutes([30, 90]));
}

node Job {
    has name: str;
    has duration: int;

    def finish_time(start_time: int) -> int {
        return start_time + self.duration;
    }
}

edge DependsOn {
    has note: str = "required before next job";
}

walker ScheduleStats {
    has total_duration: int = 0;
    has longest_job: int = 0;

    def record(duration: int) -> int {
        self.total_duration = self.total_duration + duration;
        if duration > self.longest_job {
            self.longest_job = duration;
        }
        return self.total_duration;
    }
}

def buffered_duration(durations: list[int], buffer: int) -> int {
    total: int = 0;
    for duration in durations {
        total = total + duration + buffer;
    }
    return total;
}

with entry {
    root() ++> node::Job(name="extract", duration=20);
    root() ++> node::Job(name="transform", duration=40);
    root() ++> node::Job(name="load", duration=15);
    print(buffered_duration([20, 40, 15], 5));
}
